class Solution:
    def reformatNumber(self, number: str) -> str:
        digits = number.replace(' ', '').replace('-', '')
        result = []
        while len(digits) > 4:
            result.append(digits[:3])
            digits = digits[3:]
        if len(digits) == 2:
            result.append(digits)
        elif len(digits) == 3:
            result.append(digits)
        elif len(digits) == 4:
            result.append(digits[:2])
            result.append(digits[2:])
        return '-'.join(result)
